const output = $input.item.json.text || '';
let classificacao;
try {
  const match = output.match(/\{[\s\S]*\}/);
  if (match) {
    classificacao = JSON.parse(match[0]);
  } else {
    throw new Error('Sem JSON');
  }
} catch(e) {
  classificacao = {
    urgencia: 'NORMAL',
    categoria: 'sistemas',
    motivo: 'Erro de parse: ' + e.message,
    responsavel: 'Sistemas',
    prazo_horas: 24
  };
}
const wh = $('Webhook Chamado').item.json.body || {};
return {
  json: {
    success: true,
    id: wh.id || 'VSA-' + Date.now(),
    titulo: wh.titulo,
    nome: wh.nome,
    email: wh.email,
    status: 'ABERTO',
    classificacao
  }
};
